import { evaluate } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base functionality
  it.todo("returns an empty results array for an empty steps list");
  it.todo("quotes a single sword for a brand-new customer (base + first-insurance surcharge + processing fee)");
  it.todo("sums base premiums for multiple main items in a single quote");
  it.todo("prices a single component (rune) using the per-component price");
  it.todo("prices a block of three alike components using the special block price");

  // Quote: per-item modifiers
  it.todo("adds a 50% surcharge for a cursed item");
  it.todo("adds a 30% surcharge for a highly enchanted item (enchantment >= 5)");

  // Quote: customer / contract modifiers
  it.todo("applies a 20% loyalty discount for customers with >= 2 years");
  it.todo("applies a 15% subsequent-contract discount instead of the first-insurance surcharge on later quotes");

  // Quote: rounding
  it.todo("rounds the premium up to the next whole G (MHPCO's favor)");

  // Claim: base functionality
  it.todo("applies a 100 G deductible to a simple claim and reduces remainingCap by the payout");
  it.todo("reimburses 50% of the damage amount for items with enchantment >= 8");
  it.todo("reimburses 100% of the damage amount for items made of dragon material");
  it.todo("caps payout at twice the insurance sum");
  it.todo("shares one cap across multiple claims on the same policy");
});

