type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const roundUp = (value: number): number => Math.ceil(value - 1e-9);

export const evaluate = (scenario: Scenario): { results: QuoteResult[] } => {
  return {
    results: scenario.steps.map((step) => {
      const itemsTotal = step.items.reduce(
        (sum, item) => sum + BASE_PREMIUM[item.type],
        0,
      );
      const premium = roundUp(itemsTotal * 1.1) + 5;
      return { premium };
    }),
  };
};

