const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const roundUp = (value: number): number => Math.ceil(value - 1e-9);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const basePremiumForGroup = (type: string, count: number): number => {
  if (type === "rune") {
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    return blocks * COMPONENT_BLOCK_PRICE + remainder * BASE_PREMIUM[type];
  }
  return count * BASE_PREMIUM[type];
};

const itemsBaseTotal = (items: Item[]): number => {
  const counts = countByType(items);
  return Object.entries(counts).reduce(
    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
    0,
  );
};

export const evaluate = (scenario: Scenario): { results: QuoteResult[] } => {
  return {
    results: scenario.steps.map((step) => {
      const premium = roundUp(itemsBaseTotal(step.items) * 1.1) + PROCESSING_FEE;
      return { premium };
    }),
  };
};

