type Item = { type: string; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const roundUp = (value: number): number => Math.ceil(value - 1e-9);

const isComponent = (item: Item): boolean => item.type === "rune";

const itemBasePremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return item.cursed ? base * 1.5 : base;
};

const componentBaseTotal = (components: Item[]): number => {
  const count = components.length;
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const remainder = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_PRICE + remainder * BASE_PREMIUM.rune;
};

const itemsBaseTotal = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mains = items.filter((item) => !isComponent(item));
  const mainTotal = mains.reduce((sum, item) => sum + itemBasePremium(item), 0);
  return mainTotal + componentBaseTotal(components);
};

const computePremium = (items: Item[]): number => {
  return roundUp(itemsBaseTotal(items) * 1.1) + PROCESSING_FEE;
};

export const evaluate = (scenario: Scenario): { results: QuoteResult[] } => {
  return {
    results: scenario.steps.map((step) => ({
      premium: computePremium(step.items),
    })),
  };
};

