  it.todo("reimburses 50% of the damage amount for items with enchantment >= 8");
  it.todo("reimburses 100% of the damage amount for items made of dragon material");
  it.todo("caps payout at twice the insurance sum");
  it.todo("shares one cap across multiple claims on the same policy");
});

