  const policies: Policy[] = [];
  const results: StepResult[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const { result, policy } = processQuote(
        step,
        scenario.customer,
        index === 0,
      );
      policies[index] = policy;
      return result;
    }
    return processClaim(step, policies);
  });
  return { results };
};

